.darma-loader-wave-bars {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  height: 52px;
  color: var(--loader-color, #6366f1);
}
.darma-loader-wave-bars i {
  width: 7px;
  height: 40px;
  border-radius: 999px;
  background: currentColor;
  animation: darma-loader-wave-bars-wave 1s ease-in-out infinite;
}
.darma-loader-wave-bars i:nth-child(2) { animation-delay: 0.1s; }
.darma-loader-wave-bars i:nth-child(3) { animation-delay: 0.2s; }
.darma-loader-wave-bars i:nth-child(4) { animation-delay: 0.3s; }
.darma-loader-wave-bars i:nth-child(5) { animation-delay: 0.4s; }
@keyframes darma-loader-wave-bars-wave {
  0%, 100% { transform: scaleY(0.38); opacity: 0.38; }
  50% { transform: scaleY(1); opacity: 1; }
}

